\int_{-R}^{R}e^{-i\omega t}dt
&=\left[\frac{e^{-i\omega t}}{-i\omega}\right]_{-R}^{R} \\
&=\frac{e^{-i\omega R}-e^{i\omega R}}{-i\omega} \\
&=\frac{e^{i\omega R}-e^{-i\omega R}}{i\omega} \\
&=\frac{2i\sin(\omega R)}{i\omega} \\
&=\frac{2\sin(\omega R)}{\omega}
\end{aligned}

